import{_ as e,o as a,c as r,ai as d}from"./chunks/framework.DyvBZb4W.js";const u=JSON.parse('{"title":"Synergy Details","description":"","frontmatter":{},"headers":[],"relativePath":"en/mods/xuanji-character/synergies.md","filePath":"en/mods/xuanji-character/synergies.md","lastUpdated":1782051941000}'),n={name:"en/mods/xuanji-character/synergies.md"};function i(o,t,h,s,l,c){return a(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="synergy-details" tabindex="-1">Synergy Details <a class="header-anchor" href="#synergy-details" aria-label="Permalink to &quot;Synergy Details&quot;">​</a></h1><p>This page lists the current <code>0.13.0-beta</code> synergy thresholds, Machine Core main effects, and tier effects for Xuanji. It has been rechecked against the current public preview implementation, and values may still change during Beta.</p><h2 id="general-rules" tabindex="-1">General Rules <a class="header-anchor" href="#general-rules" aria-label="Permalink to &quot;General Rules&quot;">​</a></h2><ul><li>Cards with Encode enter the Machine Chamber after being played. When the chamber reaches 3 cards, they condense into a Machine Core.</li><li>In a single Machine Core, each synergy can contribute at most 4 progress.</li><li>The main trait is the highest-contribution synergy. Ties use the earliest chamber card&#39;s first tied tag.</li><li>The Machine Core Board holds up to 3 cores. New cores enter from the left; if the board is full, the rightmost core is removed.</li><li>Synergy progress comes from the total contribution of all current Machine Cores. Command can add extra effective progress after its Gold tier.</li></ul><h2 id="bulwark" tabindex="-1">Bulwark <a class="header-anchor" href="#bulwark" aria-label="Permalink to &quot;Bulwark&quot;">​</a></h2><p>Machine Core main effect: at turn start, each Bulwark Machine Core grants 3 Block.</p><table tabindex="0"><thead><tr><th>Tier</th><th style="text-align:right;">Progress</th><th>Effect</th></tr></thead><tbody><tr><td>Bronze</td><td style="text-align:right;">2</td><td>Whenever you gain Block from your own cards, gain 2 additional Block.</td></tr><tr><td>Silver</td><td style="text-align:right;">5</td><td>At turn start, if you have any Machine Core, gain 6 Block.</td></tr><tr><td>Gold</td><td style="text-align:right;">8</td><td>Block is no longer removed at the start of your turn.</td></tr><tr><td>Chromatic</td><td style="text-align:right;">11</td><td>After taking attack damage, reflect the damage absorbed by Block back to the attacker.</td></tr></tbody></table><h2 id="ambush" tabindex="-1">Ambush <a class="header-anchor" href="#ambush" aria-label="Permalink to &quot;Ambush&quot;">​</a></h2><p>Machine Core main effect: the first Attack you play each turn deals 3 bonus damage per Ambush Machine Core.</p><table tabindex="0"><thead><tr><th>Tier</th><th style="text-align:right;">Progress</th><th>Effect</th></tr></thead><tbody><tr><td>Bronze</td><td style="text-align:right;">3</td><td>At turn start, gain 3 Vigor.</td></tr><tr><td>Silver</td><td style="text-align:right;">5</td><td>At turn start, gain 5 Vigor instead.</td></tr><tr><td>Gold</td><td style="text-align:right;">8</td><td>At turn start, gain 5 temporary Strength for this turn.</td></tr><tr><td>Chromatic</td><td style="text-align:right;">12</td><td>At turn start, add an extra Ambush Attack card to your hand.</td></tr></tbody></table><h2 id="insight" tabindex="-1">Insight <a class="header-anchor" href="#insight" aria-label="Permalink to &quot;Insight&quot;">​</a></h2><p>Machine Core main effect: when you encode, draw 1 card, up to once per turn.</p><table tabindex="0"><thead><tr><th>Tier</th><th style="text-align:right;">Progress</th><th>Effect</th></tr></thead><tbody><tr><td>Bronze</td><td style="text-align:right;">3</td><td>The first time you condense each turn, draw 1 card.</td></tr><tr><td>Silver</td><td style="text-align:right;">6</td><td>The first time you encode each turn, draw 1 additional card.</td></tr><tr><td>Gold</td><td style="text-align:right;">9</td><td>Normal hand draw draws 1 extra card; after turn start, discard 1 card and you may exhaust up to 2 cards from hand; the first Skill you play each turn draws 1 card.</td></tr><tr><td>Chromatic</td><td style="text-align:right;">12</td><td>Whenever you draw one of your cards, deal 7 damage to all enemies.</td></tr></tbody></table><h2 id="overload" tabindex="-1">Overload <a class="header-anchor" href="#overload" aria-label="Permalink to &quot;Overload&quot;">​</a></h2><p>Machine Core main effect: after the first Machine Core you condense each turn, gain 1 Energy for each Overload Machine Core.</p><table tabindex="0"><thead><tr><th>Tier</th><th style="text-align:right;">Progress</th><th>Effect</th></tr></thead><tbody><tr><td>Bronze</td><td style="text-align:right;">3</td><td>After the first Machine Core you condense each turn, gain 1 additional Energy.</td></tr><tr><td>Silver</td><td style="text-align:right;">5</td><td>Gain +1 max Energy.</td></tr><tr><td>Gold</td><td style="text-align:right;">8</td><td>Unspent Energy is retained into the next turn.</td></tr><tr><td>Chromatic</td><td style="text-align:right;">11</td><td>At turn start, deal damage to all enemies equal to 15 times your current Energy.</td></tr></tbody></table><h2 id="momentum" tabindex="-1">Momentum <a class="header-anchor" href="#momentum" aria-label="Permalink to &quot;Momentum&quot;">​</a></h2><p>Machine Core main effect: at end of turn, if you did not condense a Machine Core this turn, gain 1 Gold per Momentum Machine Core, up to 12 Gold per combat.</p><table tabindex="0"><thead><tr><th>Tier</th><th style="text-align:right;">Progress</th><th>Effect</th></tr></thead><tbody><tr><td>Bronze</td><td style="text-align:right;">3</td><td>At end of turn, gain 4 Gold, up to 12 Gold per combat.</td></tr><tr><td>Silver</td><td style="text-align:right;">6</td><td>That end-of-turn reward becomes 16 Gold, up to 48 Gold per combat.</td></tr><tr><td>Gold</td><td style="text-align:right;">9</td><td>On combat victory, gain 3 Max HP.</td></tr><tr><td>Chromatic</td><td style="text-align:right;">12</td><td>At turn start, up to 3 times per combat, upgrade a random upgradable card in your deck; if none can be upgraded, add 1 Replay to a random deck card. On combat victory, gain or stack Momentum Emblem.</td></tr></tbody></table><p>Momentum Emblem: at combat start, gain 1 Strength and 1 Dexterity for each counter.</p><h2 id="transmute" tabindex="-1">Transmute <a class="header-anchor" href="#transmute" aria-label="Permalink to &quot;Transmute&quot;">​</a></h2><p>Machine Core main effect: the first time you exhaust one of your cards each turn, draw 1 card per Transmute Machine Core.</p><table tabindex="0"><thead><tr><th>Tier</th><th style="text-align:right;">Progress</th><th>Effect</th></tr></thead><tbody><tr><td>Bronze</td><td style="text-align:right;">3</td><td>The first time you encode each turn, you may exhaust 1 card from your hand.</td></tr><tr><td>Silver</td><td style="text-align:right;">6</td><td>At the start of each turn, add 1 random card from your own character pool to your hand; it has Void.</td></tr><tr><td>Gold</td><td style="text-align:right;">9</td><td>Whenever you exhaust one of your cards, gain 1 Energy.</td></tr><tr><td>Chromatic</td><td style="text-align:right;">12</td><td>Whenever you exhaust 2 cards, add 1 random card from all characters to your hand; it gains Exhaust and costs 0 this combat.</td></tr></tbody></table><h2 id="corrosion" tabindex="-1">Corrosion <a class="header-anchor" href="#corrosion" aria-label="Permalink to &quot;Corrosion&quot;">​</a></h2><p>Machine Core main effect: at turn start, apply 1 Poison to the highest-HP enemy for each Corrosion Machine Core.</p><table tabindex="0"><thead><tr><th>Tier</th><th style="text-align:right;">Progress</th><th>Effect</th></tr></thead><tbody><tr><td>Bronze</td><td style="text-align:right;">2</td><td>At turn start, apply 2 Poison and 1 Weak to the highest-HP enemy.</td></tr><tr><td>Silver</td><td style="text-align:right;">5</td><td>At turn start, apply 2 Poison and 1 Vulnerable to the lowest-HP enemy.</td></tr><tr><td>Gold</td><td style="text-align:right;">8</td><td>At turn start, apply 2 Poison, 1 Weak, and 1 Vulnerable to all enemies.</td></tr><tr><td>Chromatic</td><td style="text-align:right;">11</td><td>At turn start, additionally apply 25 Poison to all enemies.</td></tr></tbody></table><h2 id="command" tabindex="-1">Command <a class="header-anchor" href="#command" aria-label="Permalink to &quot;Command&quot;">​</a></h2><p>Machine Core main effect: whenever another main Machine Core effect triggers, gain 1 Block per Command Machine Core, up to 3 times per turn.</p><table tabindex="0"><thead><tr><th>Tier</th><th style="text-align:right;">Progress</th><th>Effect</th></tr></thead><tbody><tr><td>Bronze</td><td style="text-align:right;">3</td><td>The first time you encode each turn, gain 5 Block.</td></tr><tr><td>Silver</td><td style="text-align:right;">6</td><td>Whenever another synergy triggers, gain 3 Block.</td></tr><tr><td>Gold</td><td style="text-align:right;">9</td><td>Whenever another synergy triggers, also draw 1 card and gain 1 Energy, up to 2 times per turn. All synergies gain +1 effective progress.</td></tr><tr><td>Chromatic</td><td style="text-align:right;">12</td><td>All synergies gain an additional +3 progress. Whenever another synergy triggers, deal 12 damage to all enemies and gain 20 Block.</td></tr></tbody></table><p>Command&#39;s progress bonus affects displayed effective progress and threshold checks, so a mature Command engine can push other synergies into higher tiers.</p><h2 id="links" tabindex="-1">Links <a class="header-anchor" href="#links" aria-label="Permalink to &quot;Links&quot;">​</a></h2><ul><li>Back to <a href="/jasonsong-games/en/mods/xuanji-character/">Xuanji Character Mod</a></li><li>See <a href="/jasonsong-games/en/mods/xuanji-character/faq">FAQ</a></li></ul>',32)])])}const m=e(n,[["render",i]]);export{u as __pageData,m as default};
